// Resolve a shop name to {brand, cat}, handling truncated names (e.g. "凱悅國際貿易通化分…")
export function resolveShop(name) {
  if (!name) return { brand: name || "未知", cat: "其他" };
  const clean = name.replace(/…$/, "").trim();
  // Direct match
  if (SHOP_MAP[clean]) return SHOP_MAP[clean];
  if (SHOP_MAP[name]) return SHOP_MAP[name];
  // Partial match: shop key starts with cleaned name or vice versa
  for (const key of Object.keys(SHOP_MAP)) {
    if (clean.length >= 2 && (key.startsWith(clean) || clean.startsWith(key))) {
      return SHOP_MAP[key];
    }
  }
  return { brand: clean, cat: "其他" };
}

export default SHOP_MAP;

